--[[
  API-Overview:
    ZidiuUI:CreateWindow(title)                             → Window
    Window:CreateTab(name, icon)                           → Tab
    Tab:CreateSection(name)                                → Section
    Section:CreateButton(text, callback)                   → Button
    Section:CreateToggle(text, default, cb)                → Toggle
    Section:CreateDropdown(text, opts, cb)                 → Dropdown (.Refresh)
    Section:CreateMultiDropdown(text, opts, cb)            → MultiDropdown (.Refresh)
    Section:CreateTextbox(text, placeholder, cb)           → Textbox (.SetText)
    Section:CreateSlider(text, min, max, default, cb)      → Slider
    Section:CreateKeybind(text, default, cb)               → Keybind
    Section:CreateLabel(text)                              → Label (.SetText)
    Section:CreateSearchDropdown(label, opts, cb, multi)   → SearchDropdown
    Section:CreateDualSlider(label, min, max, dMin, dMax, cb) → DualSlider
    Section:CreateExLabel(title, text)                     → ExLabel (.SetText, .SetTitle, .Open, .Close, .Focus, .Destroy)
    element:SetTooltip(text)                               → sets "?" button + tooltip popup
    ZidiuUI:Notify(message, type, duration)                → Toast-Notification (info/success/error/warning)
    ZidiuUI:SetToastPosition(pos)                          → "bottom-center", "bottom-right", "top-center"
    ZidiuUI:ShowTooltip(text, position)                    → (deprecated, kept for compatibility)
    ZidiuUI:HideTooltip()                                  → (deprecated)

NOTE: The changelog tab is added AUTOMATICALLY to every window!
More info: https://github.com/musicmaker-web/ZidiuUI/blob/main/README.md
]]--

